```python
def fizzbuzz(n: int) -> str:
    """
    Returns 'Fizz' for multiples of 3, 'Buzz' for multiples of 5, 
    'FizzBuzz' for multiples of both, or the number as a string otherwise.

    Args:
        n: The integer to check.

    Returns:
        A string indicating the result based on the rules above.
    """
    if n % 3 == 0 and n % 5 == 0:
        return 'FizzBuzz'
    elif n % 3 == 0:
        return 'Fizz'
    elif n % 5 == 0:
        return 'Buzz'
    else:
        return str(n)

